mapper.select:
select id, stat_date, city, keyword, tfidf_score, job_count, rank_no, data_batch_no
from analysis_skill_tfidf
where stat_date = (
    select max(stat_date)
    from analysis_skill_tfidf
)

    and city = #{city}

order by rank_no asc, tfidf_score desc
limit #{limit}

select city
from (
    select city, min(rank_no) as min_rank
    from analysis_skill_tfidf
    where stat_date = (
        select max(stat_date)
        from analysis_skill_tfidf
    )
      and city != '全省'
    group by city
    order by min_rank asc, city asc
    limit #{limit}
) t
